// Mixbench OpenCL Kernel
// Translated from OpenMP CPU benchmark to OpenCL GPU benchmark

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

// Kernel parameters are set via build definitions:
// - class_T: data type (float, double, int, half2, short)
// - blockdim: workgroup size
// - COMPUTE_ITERATIONS: number of computation iterations
// - ELEMENTS_PER_THREAD: elements processed per workitem
// - FUSION_DEGREE: fusion degree for computation
// - BLOCK_STRIDED: whether to use workgroup-strided access

typedef class_T element_t;

#ifdef ENABLE_HP
typedef half2 element_half2_t;
#endif

__attribute__((noinline))
element_t bench_block(element_t* data, element_t f, size_t static_chunk_size) {
    element_t sum = (element_t)0;

#ifdef BASELINE_IMPL
    for (size_t i = 0; i < static_chunk_size; i++) {
        element_t t = data[i];
        for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
            t = t * t + f;
        }
        sum += t;
    }
#else
    element_t f_arr[8];
    for (int k = 0; k < 8; k++) {
        f_arr[k] = f;
    }

    for (size_t i = 0; i < static_chunk_size; i++) {
        element_t t_arr[8];
        for (int k = 0; k < 8; k++) {
            t_arr[k] = data[i];
        }

        for (size_t j = 0; j < COMPUTE_ITERATIONS / 8; j++) {
            for (int k = 0; k < 8; k++) {
                t_arr[k] = t_arr[k] * t_arr[k] + f_arr[k];
            }
        }

        // Handle remainder iterations
        int remainder = COMPUTE_ITERATIONS % 8;
        for (int k = 0; k < remainder; k++) {
            t_arr[k] = t_arr[k] * t_arr[k] + f_arr[k];
        }

        for (int k = 0; k < 8; k++) {
            sum += t_arr[k];
        }
    }
#endif

    return sum;
}

__kernel void benchmark_func(element_t seed, __global element_t* data) {
    size_t wi_id = get_global_id(0);
    size_t total_wi = get_global_size(0);
    size_t wg_id = get_group_id(0);
    size_t wg_size = get_local_size(0);

    element_t sum = (element_t)0;
    constexpr size_t static_chunk_size = 4096;

#ifdef BLOCK_STRIDED
    // Workgroup-strided access pattern
    size_t stride = wg_size * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t base_idx = wg_id * stride;
    size_t wi_offset = (wi_id - wg_id * wg_size) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    for (size_t base = 0; base < static_chunk_size; base++) {
        for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
            for (size_t elem = 0; elem < ELEMENTS_PER_THREAD; elem++) {
                size_t idx = base_idx + wi_offset + fusion * ELEMENTS_PER_THREAD + elem + base * stride;
                if (idx < total_wi * ELEMENTS_PER_THREAD * FUSION_DEGREE) {
                    element_t t = data[idx];
                    for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
                        t = t * t + seed;
                    }
                    sum += t;
                }
            }
        }
    }
#else
    // NDRange-strided access pattern (default)
    size_t total_elements = total_wi * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t wi_start = wi_id * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    for (size_t base = 0; base < static_chunk_size; base++) {
        for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
            for (size_t elem = 0; elem < ELEMENTS_PER_THREAD; elem++) {
                size_t idx = wi_start + fusion * ELEMENTS_PER_THREAD + elem + base * total_wi * ELEMENTS_PER_THREAD * FUSION_DEGREE;
                if (idx < total_elements) {
                    element_t t = data[idx];
                    for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
                        t = t * t + seed;
                    }
                    sum += t;
                }
            }
        }
    }
#endif

    // Store result at workitem's base position
    if (wi_id < total_wi) {
        data[wi_id * ELEMENTS_PER_THREAD * FUSION_DEGREE] = sum;
    }
}

// Warmup kernel for initialization
__kernel void benchmark_func_warmup(short seed, __global element_t* data) {
    size_t idx = get_global_id(0);
    size_t total = get_global_size(0);

    if (idx < total) {
        element_t t = data[idx];
        for (int j = 0; j < 16; j++) {
            t = t * t + (element_t)seed;
        }
        data[idx] = t;
    }
}
